/* ───────── helpers ───────── */

function initials(name: string): string {
  return name
    .split(/\s+/)
    .map((p) => p[0])
    .filter(Boolean)
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

function fmtDate(ms: number): string {
  return new Intl.DateTimeFormat(undefined, {
    month: "short",
    day: "numeric",
    year: "numeric",
  }).format(new Date(ms));
}

/* ───────── GanttBar (Tier C) ───────── */

export type GanttBarProps = {
  leftPx: number;
  widthPx: number;
  fill: string;
  rowHeight: number;
  overdue?: boolean;
  inactive?: boolean;
  locked?: boolean;
  priorityColor?: string;
  selected?: boolean;
} & HTMLAttributes<HTMLDivElement>;

export function GanttBar({
  leftPx,
  widthPx,
  fill,
  rowHeight,
  overdue,
  inactive,
  locked,
  priorityColor,
  selected,
  className,
  style,
  ...rest
}: GanttBarProps) {
  const barH = Math.max(10, Math.min(rowHeight - 12, 22));
  return (
    <div
      data-selected={selected || undefined}
      className={cn(
        "absolute top-1/2 -translate-y-1/2 cursor-pointer rounded-[5px] shadow-sm ring-offset-background transition-shadow",
        "outline-none focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-1",
        "data-[selected]:ring-2 data-[selected]:ring-foreground/70 data-[selected]:ring-offset-1",
        inactive && "opacity-50",
        className,
      )}
      style={{
        left: leftPx,
        width: Math.max(widthPx, 6),
        height: barH,
        background: fill,
        ...style,
      }}
      {...rest}
    >
      {priorityColor ? (
        <span
          aria-hidden
          className="absolute left-0 top-0 h-full w-1 rounded-l-[5px]"
          style={{ background: priorityColor }}
        />
      ) : null}
      {overdue ? (
        <span
          aria-hidden
          className="absolute inset-y-0 right-0 w-1.5 rounded-r-[5px] bg-destructive"
        />
      ) : null}
      {locked ? (
        <span
          aria-hidden
          className="absolute right-1 top-1/2 -translate-y-1/2 text-[9px] leading-none text-background/80"
        >
          🔒
        </span>
      ) : null}
    </div>
  );
