          ? `◆ ${fmtDate(startMs)}`
          : `${fmtDate(startMs)} → ${fmtDate(endMs)}`}
      </div>
      <div className="flex items-center gap-2 pt-0.5">
        {item.targetPerson ? (
          <span className="flex items-center gap-1.5">
            <Avatar className="size-4">
              {item.targetPerson.avatar ? (
                <AvatarImage
                  src={item.targetPerson.avatar}
                  alt={item.targetPerson.name}
                />
              ) : null}
              <AvatarFallback className="text-[8px]">
                {initials(item.targetPerson.name)}
              </AvatarFallback>
            </Avatar>
            <span className="text-[11px] text-muted-foreground">
              {item.targetPerson.name}
            </span>
          </span>
        ) : null}
        {statusOpt ? (
          <Badge variant={statusOpt.variant ?? "secondary"} className="text-[10px]">
            {statusOpt.icon ? `${statusOpt.icon} ` : ""}
            {statusOpt.label}
          </Badge>
        ) : null}
      </div>
    </div>
  );
}

"use client";

import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttViewport } from "../types";
import {
  addUnit,
  isWeekend,
  majorLabel,
  minorLabel,
  pickScales,
  ticks,
  x,
} from "../lib/time-scale";

const OVERSCAN_PX = 260;

/** Tier C — dumb two-tier header from a viewport. */
export function AxisHeader({
  viewport,
  bodyWidth,
  gutterWidth,
  showWeekendShading,
  className,
}: {
  viewport: GanttViewport;
  bodyWidth: number;
  gutterWidth: number;
  showWeekendShading?: boolean;
  className?: string;
}) {
  const { minor, major } = pickScales(viewport.pxPerMs);
  const fromMs = viewport.originMs - OVERSCAN_PX / viewport.pxPerMs;
  const toMs = viewport.originMs + (bodyWidth + OVERSCAN_PX) / viewport.pxPerMs;
  const ready = bodyWidth > 0;
  const minorTicks = ready ? ticks(minor, fromMs, toMs) : [];
  const majorTicks = ready ? ticks(major, fromMs, toMs) : [];
  const weekendsOn =
    showWeekendShading && (minor === "hour" || minor === "day");

  return (
    <div className={cn("flex select-none border-b bg-card", className)}>
      <div className="shrink-0 border-r border-border" style={{ width: gutterWidth }} />
      <div className="relative grow overflow-hidden" style={{ height: 46 }}>
        {weekendsOn
          ? minorTicks
              .filter((t) => isWeekend(t))
              .map((t) => {
                const left = x(viewport, t);
                const w = x(viewport, addUnit(minor, t)) - left;
                return (
                  <div
                    key={`w${t}`}
                    aria-hidden
                    className="absolute inset-y-0 bg-muted/50"
                    style={{ left, width: w }}
                  />
                );
              })
          : null}
        {majorTicks.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit(major, t)) - left;
          return (
            <div
              key={`M${t}`}
              className="absolute top-0 flex h-6 items-center overflow-hidden whitespace-nowrap border-r border-border/60 px-2 text-xs font-medium text-foreground"
              style={{ left, width: w }}
            >
              {majorLabel(major, t)}
            </div>
          );
        })}
        {minorTicks.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit(minor, t)) - left;
          return (
            <div
              key={`m${t}`}
              className="absolute bottom-0 flex h-5 items-center justify-center overflow-hidden border-r border-border/40 text-[10px] tabular-nums text-muted-foreground"
              style={{ left, width: w }}
            >
              {minorLabel(minor, t)}
            </div>
          );
        })}
      </div>
    </div>
  );
}

/** Tier B — context-connected axis. */
export function GanttTimelineAxis({ className }: { className?: string }) {
  const { viewport, bodyWidth, gutterWidth, showWeekendShading } =
    useGanttTimeline();
  return (
    <AxisHeader
      viewport={viewport}
      bodyWidth={bodyWidth}
      gutterWidth={gutterWidth}
      showWeekendShading={showWeekendShading}
      className={className}
    />
  );
}

"use client";

/* eslint-disable react-hooks/refs -- bodyScrollRef/gutterTrackRef are bundled on the
   context value; the React Compiler's refs rule false-positives on reads taken off a
   context object (see blackboard-01). Ref reads here are confined to effects + ref= props. */

import { useEffect, useRef, useState, type PointerEvent } from "react";
import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { TodoItem } from "../types";
import { addUnit, isWeekend, pickScales, ticks, x } from "../lib/time-scale";
import {
  BarTooltip,
  GanttBar,
  MilestoneDiamond,
  SummaryBar,
  TodayLine,
} from "./gantt-bars";

type HoverState = { item: TodoItem; leftPx: number; topPx: number };

export function GanttTimelineBody({ className }: { className?: string }) {
  const ctx = useGanttTimeline();
  const scrollRef = ctx.bodyScrollRef;
  const { viewport, bodyWidth } = ctx;

  const [hover, setHover] = useState<HoverState | null>(null);

  /* ── measure width ── */
  const setBodyWidth = ctx.setBodyWidth;
  useEffect(() => {
    const el = scrollRef.current;
    if (!el) return;
    const update = () => setBodyWidth(el.clientWidth);
    update();
    const ro = new ResizeObserver(update);
    ro.observe(el);
    return () => ro.disconnect();
  }, [scrollRef, setBodyWidth]);

  /* ── wheel (non-passive: plain vertical = native scroll; shift/horizontal = pan; ⌘/ctrl = zoom) ── */
  const { onZoomAt, onPan, disableGestures } = ctx;
  useEffect(() => {
    const el = scrollRef.current;
    if (!el || disableGestures) return;
    const onWheel = (e: WheelEvent) => {
      if (e.ctrlKey || e.metaKey) {
        e.preventDefault();
        const rect = el.getBoundingClientRect();
        onZoomAt(Math.exp(-e.deltaY * 0.0015), e.clientX - rect.left);
      } else if (e.shiftKey || Math.abs(e.deltaX) > Math.abs(e.deltaY)) {
        e.preventDefault();
        onPan(-(e.deltaX || e.deltaY));
      }
      // plain vertical wheel → native row scroll
    };
    el.addEventListener("wheel", onWheel, { passive: false });
    return () => el.removeEventListener("wheel", onWheel);
  }, [scrollRef, disableGestures, onZoomAt, onPan]);

  /* ── pointer gestures (drag-pan + dominant-lock + momentum + pinch) ── */
  const pointers = useRef(new Map<number, { x: number; y: number }>());
  const lockRef = useRef<null | "h" | "v">(null);
  const pinchRef = useRef<number | null>(null);
  const velRef = useRef(0);
  const lastRef = useRef<{ x: number; t: number } | null>(null);

  function onPointerDown(e: PointerEvent<HTMLDivElement>) {
    if (disableGestures) return;
    e.currentTarget.setPointerCapture(e.pointerId);
    pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });
    setHover(null);
    if (pointers.current.size === 2) {
      const [a, b] = [...pointers.current.values()];
      pinchRef.current = Math.hypot(a.x - b.x, a.y - b.y);
      lockRef.current = null;
    } else {
      ctx.beginPan();
      lockRef.current = null;
      lastRef.current = { x: e.clientX, t: e.timeStamp };
      velRef.current = 0;
    }
  }

  function onPointerMove(e: PointerEvent<HTMLDivElement>) {
    if (disableGestures) return;
    const prev = pointers.current.get(e.pointerId);
    if (!prev) return;
    const dx = e.clientX - prev.x;
    const dy = e.clientY - prev.y;
    pointers.current.set(e.pointerId, { x: e.clientX, y: e.clientY });

    if (pointers.current.size >= 2 && pinchRef.current != null) {
      const [a, b] = [...pointers.current.values()];
      const dist = Math.hypot(a.x - b.x, a.y - b.y);
      if (dist > 0 && pinchRef.current > 0) {
        const rect = e.currentTarget.getBoundingClientRect();
        onZoomAt(dist / pinchRef.current, (a.x + b.x) / 2 - rect.left);
      }
      pinchRef.current = dist;
      return;
    }
    if (pointers.current.size === 1) {
      if (!lockRef.current) {
        if (Math.abs(dx) > Math.abs(dy) && Math.abs(dx) > 3) lockRef.current = "h";
        else if (Math.abs(dy) > 3) lockRef.current = "v";
      }
      if (lockRef.current === "h") {
        onPan(dx);
        const last = lastRef.current;
        const t = e.timeStamp;
        if (last && t > last.t) velRef.current = (e.clientX - last.x) / (t - last.t);
        lastRef.current = { x: e.clientX, t };
      } else if (lockRef.current === "v" && e.pointerType === "mouse") {
        const el = scrollRef.current;
        if (el) el.scrollTop -= dy;
      }
    }
  }

  function endPointer(e: PointerEvent<HTMLDivElement>) {
    if (!pointers.current.has(e.pointerId)) return;
    pointers.current.delete(e.pointerId);
    if (pointers.current.size < 2) pinchRef.current = null;
    if (pointers.current.size === 0) {
      if (lockRef.current === "h") {
        // Drop a stale velocity: if the pointer paused before release (last move
        // > 100ms ago) the gesture has already stopped — no fling.
        const last = lastRef.current;
        const fresh = last != null && e.timeStamp - last.t <= 100;
        ctx.endPanWithVelocity(fresh ? velRef.current : 0);
      }
      lockRef.current = null;
      lastRef.current = null;
    }
  }

  /* ── weekend bands ── */
  const { minor } = pickScales(viewport.pxPerMs);
  const weekendsOn = ctx.showWeekendShading && (minor === "hour" || minor === "day");
  const dayBands =
    weekendsOn && bodyWidth > 0
      ? ticks(
          "day",
          viewport.originMs - 86_400_000,
          viewport.originMs + bodyWidth / viewport.pxPerMs,
        ).filter(isWeekend)
      : [];

  const todayLeft = x(viewport, ctx.nowMs);
  const showToday =
    ctx.showTodayLine && todayLeft >= -2 && todayLeft <= bodyWidth + 2;

  function activate(item: TodoItem) {
    ctx.setFocusedId(item.id);
    ctx.select(item.id);
    ctx.onTaskClick?.(item);
  }

  return (
    <div
      ref={scrollRef}
      onScroll={(e) => ctx.onBodyScroll(e.currentTarget.scrollTop)}
      onPointerDown={onPointerDown}
      onPointerMove={onPointerMove}
      onPointerUp={endPointer}
      onPointerCancel={endPointer}
      style={{ touchAction: disableGestures ? undefined : "pan-y" }}
      className={cn(
        "relative h-full grow overflow-x-hidden overflow-y-auto bg-background",
        !disableGestures && "cursor-grab active:cursor-grabbing",
        className,
      )}
    >
      <div className="relative" style={{ height: ctx.totalSize, minWidth: "100%" }}>
        {dayBands.map((t) => {
          const left = x(viewport, t);
          const w = x(viewport, addUnit("day", t)) - left;
          return (
            <div
              key={`wk${t}`}
              aria-hidden
              className="absolute inset-y-0 bg-muted/40"
              style={{ left, width: w }}
            />
          );
        })}

        {showToday ? <TodayLine leftPx={todayLeft} /> : null}

        {ctx.renderItems.map((ri) => {
          const row = ctx.rows[ri.index];
          if (!row) return null;
          const item = row.item;
          const selected = ctx.selectedId === item.id;
          const color = ctx.resolveColor(item);
          const geo = ctx.geometryFor(item);
          const priColor = item.priority
            ? ctx.priorityOptions?.find((o) => o.value === item.priority)?.color
            : undefined;

          const enter = (leftPx: number) =>
            setHover({ item, leftPx, topPx: ri.start });
          const leave = () => setHover(null);

          let shape: React.ReactNode = null;
          let labelLeft = 0;

          if (row.isSummary) {
            const span = ctx.summarySpanFor(item);
            if (span) {
              const left = x(viewport, span.startMs);
              const w = x(viewport, span.endMs) - left;
              labelLeft = left + Math.max(w, 8) + 6;
              shape = (
                <SummaryBar
                  leftPx={left}
                  widthPx={w}
                  selected={selected}
                  aria-hidden
                  onClick={() => activate(item)}
                  onMouseEnter={() => enter(left)}
                  onMouseLeave={leave}
                />
              );
            }
          } else if (geo.isMilestone) {
            const left = x(viewport, geo.startMs);
            labelLeft = left + 10;
            shape = (
              <MilestoneDiamond
                leftPx={left}
                fill={color.fill}
                selected={selected}
                aria-hidden
                onClick={() => activate(item)}
                onMouseEnter={() => enter(left)}
                onMouseLeave={leave}
              />
            );
          } else if (geo.endMs != null) {
            const left = x(viewport, geo.startMs);
            const w = x(viewport, geo.endMs) - left;
            labelLeft = left + Math.max(w, 6) + 6;
            shape = (
              <GanttBar
                leftPx={left}
                widthPx={w}
                fill={color.fill}
                rowHeight={ctx.rowHeight}
                overdue={color.isOverdue}
                inactive={!item.active}
                locked={item.locked}
                priorityColor={priColor}
                selected={selected}
                aria-hidden
                onClick={() => activate(item)}
                onMouseEnter={() => enter(left)}
                onMouseLeave={leave}
              />
            );
          }

          return (
            <div
              key={item.id}
              className={cn(
                "absolute inset-x-0 border-b border-border/40",
                selected && "bg-accent/40",
              )}
              style={{ top: ri.start, height: ctx.rowHeight }}
            >
              {shape}
              {labelLeft < bodyWidth + 40 ? (
                <span
                  className={cn(
                    "pointer-events-none absolute top-1/2 max-w-55 -translate-y-1/2 truncate text-xs",
                    row.isSummary ? "font-medium text-foreground" : "text-foreground/85",
                  )}
                  style={{ left: labelLeft }}
                >
                  {item.name}
                </span>
              ) : null}
            </div>
          );
        })}

        {hover ? (
          <div
            className="pointer-events-none absolute z-30 rounded-md border border-border bg-popover p-2.5 text-popover-foreground shadow-md"
            style={{
              left: Math.max(4, Math.min(hover.leftPx, Math.max(4, bodyWidth - 200))),
              top: hover.topPx > 96 ? hover.topPx - 8 : hover.topPx + ctx.rowHeight + 6,
              transform: hover.topPx > 96 ? "translateY(-100%)" : undefined,
            }}
          >
            {ctx.renderTooltip?.(hover.item) ?? (
              <BarTooltip item={hover.item} statusOptions={ctx.statusOptions} />
            )}
          </div>
        ) : null}
      </div>
    </div>
  );
}

"use client";

/* eslint-disable react-hooks/refs -- gutterTrackRef is bundled on the context value; the
   React Compiler's refs rule false-positives on reads taken off a context object (see
   blackboard-01). The ref is used only as a ref= prop + read inside effects. */

import { useEffect, useRef, type KeyboardEvent } from "react";
import { ChevronRight } from "lucide-react";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Badge } from "@/components/ui/badge";
import { cn } from "@/lib/utils";
import { useGanttTimeline } from "../hooks/use-gantt-context";
import type { GanttRow, TodoLabelOption, TodoStatusOption } from "../types";
import { effEndMs, effStartMs } from "../lib/geometry";

function initials(name: string): string {
  return name
    .split(/\s+/)
    .map((p) => p[0])
    .filter(Boolean)
    .slice(0, 2)
    .join("")
    .toUpperCase();
}

function rowAriaLabel(row: GanttRow, statusOpt?: TodoStatusOption): string {
  const { item } = row;
  const start = new Date(effStartMs(item)).toLocaleDateString();
  const end = effEndMs(item);
  const when = end == null ? `milestone ${start}` : `${start} to ${new Date(end).toLocaleDateString()}`;
  const status = statusOpt ? `, ${statusOpt.label}` : "";
  return `${item.name}, ${when}${status}`;
}

/* ───────── GutterRow (Tier C) ───────── */

export function GutterRow({
  row,
  statusOptions,
  labelOptions,
  selected,
  tabIndex,
  onToggle,
  onActivate,
}: {
  row: GanttRow;
  statusOptions?: TodoStatusOption[];
  labelOptions?: TodoLabelOption[];
  selected?: boolean;
  tabIndex: number;
  onToggle: () => void;
  onActivate: () => void;
}) {
  const { item, depth, hasChildren, collapsed } = row;
  const statusOpt = statusOptions?.find((o) => o.value === item.status);
  const dots = (item.labels ?? [])
    .map((key) => labelOptions?.find((o) => o.value === key))
    .filter(Boolean)
    .slice(0, 4) as TodoLabelOption[];

  return (
    <div
      role="treeitem"
      aria-level={depth + 1}
      aria-expanded={hasChildren ? !collapsed : undefined}
      aria-selected={selected || undefined}
      aria-label={rowAriaLabel(row, statusOpt)}
      data-rowid={item.id}
      tabIndex={tabIndex}
      onClick={onActivate}
      className={cn(
        "flex h-full cursor-default select-none items-center gap-1.5 border-b border-border/40 pr-2 outline-none",
        "focus-visible:bg-accent focus-visible:ring-1 focus-visible:ring-inset focus-visible:ring-ring",
        selected && "bg-accent",
        !item.active && "opacity-60",
      )}
      style={{ paddingLeft: 8 + depth * 16 }}
    >
      {hasChildren ? (
        <button
          type="button"
          tabIndex={-1}
          aria-label={collapsed ? "Expand" : "Collapse"}
          onClick={(e) => {
            e.stopPropagation();
            onToggle();
          }}
          className="grid size-4 shrink-0 place-items-center rounded text-muted-foreground hover:bg-muted hover:text-foreground"
        >
          <ChevronRight
            className={cn("size-3.5 transition-transform", !collapsed && "rotate-90")}
          />
        </button>
      ) : (
        <span className="inline-block w-4 shrink-0" />
      )}

      {item.targetPerson ? (
        <Avatar className="size-5 shrink-0">
          {item.targetPerson.avatar ? (
            <AvatarImage src={item.targetPerson.avatar} alt={item.targetPerson.name} />
          ) : null}
          <AvatarFallback className="text-[9px]">
            {initials(item.targetPerson.name)}
          </AvatarFallback>
        </Avatar>
      ) : null}

      <span className="truncate text-sm text-foreground">{item.name}</span>

      {dots.length > 0 ? (
        <span className="ml-auto flex shrink-0 items-center gap-1">
          {dots.map((d) => (
            <span
              key={d.value}
              title={d.label}
              className="size-2 rounded-full"
              style={{ background: d.color ?? "var(--muted-foreground)" }}
            />
          ))}
        </span>
      ) : null}

      {statusOpt ? (
        <Badge
          variant={statusOpt.variant ?? "secondary"}
          className={cn("shrink-0 text-[10px]", dots.length === 0 && "ml-auto")}
        >
          {statusOpt.label}
        </Badge>
      ) : null}
    </div>
  );
}

/* ───────── GanttTimelineGutter (Tier B) ───────── */

export function GanttTimelineGutter({ className }: { className?: string }) {
  const ctx = useGanttTimeline();
  const treeRef = useRef<HTMLDivElement | null>(null);

  const rows = ctx.rows;
  const activeId = ctx.focusedId ?? rows[0]?.item.id ?? null;

  useEffect(() => {
    if (!ctx.focusedId || !treeRef.current) return;
    const safe =
      typeof CSS !== "undefined" && CSS.escape
        ? CSS.escape(ctx.focusedId)
        : ctx.focusedId.replace(/"/g, '\\"');
    const el = treeRef.current.querySelector<HTMLElement>(`[data-rowid="${safe}"]`);
    el?.focus();
  }, [ctx.focusedId]);

  function onKeyDown(e: KeyboardEvent<HTMLDivElement>) {
    const i = rows.findIndex((r) => r.item.id === activeId);
    const focusAt = (j: number) => {
      const r = rows[Math.max(0, Math.min(rows.length - 1, j))];
      if (r) ctx.setFocusedId(r.item.id);
    };
    const cur = rows[i];
    switch (e.key) {
      case "ArrowDown":
        e.preventDefault();
        focusAt(i + 1);
        break;
      case "ArrowUp":
        e.preventDefault();
        focusAt(i - 1);
        break;
      case "Home":
        e.preventDefault();
        focusAt(0);
        break;
      case "End":
        e.preventDefault();
        focusAt(rows.length - 1);
        break;
      case "ArrowRight":
        if (cur?.hasChildren && cur.collapsed) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        } else if (i < rows.length - 1) {
          e.preventDefault();
          focusAt(i + 1);
        }
        break;
      case "ArrowLeft":
        if (cur?.hasChildren && !cur.collapsed) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        } else if (cur?.parentId) {
          e.preventDefault();
          ctx.setFocusedId(cur.parentId);
        }
        break;
      case "Enter":
        if (cur) {
          e.preventDefault();
          ctx.select(cur.item.id);
          ctx.onTaskClick?.(cur.item);
        }
        break;
      case " ":
        if (cur?.hasChildren) {
          e.preventDefault();
          ctx.toggleCollapse(cur.item.id);
        }
        break;
      default:
        break;
    }
  }

  return (
    <div
      ref={treeRef}
      role="tree"
      aria-label="Task rows"
      onKeyDown={onKeyDown}
      className={cn("h-full shrink-0 overflow-hidden border-r border-border bg-card", className)}
      style={{ width: ctx.gutterWidth }}
    >
      <div ref={ctx.gutterTrackRef} className="relative" style={{ height: ctx.totalSize }}>
        {ctx.renderItems.map((ri) => {
          const row = rows[ri.index];
          if (!row) return null;
          return (
            <div
              key={row.item.id}
              className="absolute inset-x-0"
              style={{ top: ri.start, height: ctx.rowHeight }}
            >
              <GutterRow
                row={row}
                statusOptions={ctx.statusOptions}
                labelOptions={ctx.labelOptions}
                selected={ctx.selectedId === row.item.id}
                tabIndex={activeId === row.item.id ? 0 : -1}
                onToggle={() => ctx.toggleCollapse(row.item.id)}
                onActivate={() => {
                  ctx.setFocusedId(row.item.id);
                  ctx.select(row.item.id);
                  ctx.onTaskClick?.(row.item);
                }}
              />
            </div>
          );
        })}
      </div>
    </div>
  );
}

"use client";

import {
  forwardRef,
  useCallback,
  useEffect,
  useImperativeHandle,
  useMemo,
  useRef,
  useState,
} from "react";
import { cn } from "@/lib/utils";
import type {
  GanttColorResolver,
  GanttContextValue,
  GanttTimelineHandle,
  GanttTimelineRootProps,
  TodoItem,
} from "../types";
import {
  dataExtent as computeExtent,
  effStartMs,
  geometryFor as computeGeometry,
  summarySpan,
} from "../lib/geometry";
import { ancestorsOf, flatten, indexById, parentIds } from "../lib/flatten";
import { barFill, resolveRamp, toneFor } from "../lib/color";
import { useColorTick } from "../hooks/use-color-tick";
import { useGanttViewport } from "../hooks/use-gantt-viewport";
import { useGanttVirtual } from "../hooks/use-gantt-virtual";
import { GanttContext } from "../hooks/use-gantt-context";

export const GanttTimelineRoot = forwardRef<
  GanttTimelineHandle,
  GanttTimelineRootProps
>(function GanttTimelineRoot(props, ref) {
  const {
    data,
    statusOptions,
    priorityOptions,
    labelOptions,
    colorRamp,
    colorRefreshIntervalMs = 60_000,
    zoom,
    defaultZoom = "week",
    onZoomChange,
    minZoom = "hour",
    maxZoom = "quarter",
    onViewportChange,
    disableGestures = false,
    range,
    now,
    rowHeight = 36,
    gutterWidth = 280,
    showWeekendShading = false,
    defaultCollapsedIds,
    collapsedIds,
    onCollapsedChange,
    selectedId,
    onSelect,
    onTaskClick,
    renderTooltip,
    className,
    children,
  } = props;
  const ariaLabel = props["aria-label"];

  /* ── now (SSR-safe) ── */
  const tick = useColorTick(colorRefreshIntervalMs);
  const [clientNow, setClientNow] = useState<number | null>(null);
  useEffect(() => {
    if (now == null) setClientNow(Date.now());
  }, [now, tick]);
  const resolvedNow = now != null ? (typeof now === "function" ? now() : now) : null;

  const extent = useMemo(() => computeExtent(data), [data]);
  const nowMs =
    resolvedNow != null ? resolvedNow.getTime() : clientNow ?? extent.startMs;
  const showTodayLine = resolvedNow != null || clientNow != null;

  /* ── collapse (controlled / uncontrolled) ── */
  const collapseControlled = collapsedIds != null;
  const [internalCollapsed, setInternalCollapsed] = useState<Set<string>>(
    () => new Set(defaultCollapsedIds ?? []),
  );
  const collapsedSet = useMemo(
    () => (collapseControlled ? new Set(collapsedIds) : internalCollapsed),
    [collapseControlled, collapsedIds, internalCollapsed],
  );
  const setCollapsed = useCallback(
    (next: Set<string>) => {
      if (!collapseControlled) setInternalCollapsed(next);
      onCollapsedChange?.([...next]);
    },
    [collapseControlled, onCollapsedChange],
  );
  const isCollapsed = useCallback((id: string) => collapsedSet.has(id), [collapsedSet]);
  const toggleCollapse = useCallback(
    (id: string) => {
      const next = new Set(collapsedSet);
      if (next.has(id)) next.delete(id);
      else next.add(id);
      setCollapsed(next);
    },
    [collapsedSet, setCollapsed],
  );

  /* ── selection (controlled / uncontrolled) ── */
  const selControlled = selectedId !== undefined;
  const [internalSel, setInternalSel] = useState<string | null>(null);
  const selectedVal = selControlled ? selectedId ?? null : internalSel;
  const select = useCallback(
    (id: string | null) => {
      if (!selControlled) setInternalSel(id);
      onSelect?.(id);
    },
    [selControlled, onSelect],
  );

  const [focusedId, setFocusedId] = useState<string | null>(null);

  /* ── rows + virtualization ── */
  const rows = useMemo(() => flatten(data, (id) => collapsedSet.has(id)), [data, collapsedSet]);
  const rowsRef = useRef(rows);
  rowsRef.current = rows;
  const itemIndex = useMemo(() => indexById(data), [data]);

  const bodyScrollRef = useRef<HTMLDivElement | null>(null);
  const gutterTrackRef = useRef<HTMLDivElement | null>(null);
  const { renderItems, totalSize } = useGanttVirtual({
    count: rows.length,
    scrollRef: bodyScrollRef,
    rowHeight,
  });

  const [bodyWidth, setBodyWidth] = useState(0);

  /* ── viewport ── */
  const vp = useGanttViewport({
    dataExtent: extent,
    bodyWidth,
    defaultZoom,
    controlledZoom: zoom,
    onZoomChange,
    minZoom,
    maxZoom,
    onViewportChange,
    range,
    nowMs,
  });

  /* ── color + geometry closures ── */
  const ramp = useMemo(() => resolveRamp(colorRamp), [colorRamp]);
  const geometryFor = useCallback(
    (item: TodoItem) => computeGeometry(item, nowMs, toneFor(item, statusOptions)),
    [nowMs, statusOptions],
  );
  const resolveColor = useCallback<GanttColorResolver>(
    (item) => {
      const { fill, tone } = barFill(item, nowMs, ramp, statusOptions);
      return { fill, tone, isOverdue: geometryFor(item).isOverdue };
    },
    [nowMs, ramp, statusOptions, geometryFor],
  );
  const summarySpanFor = useCallback(
    (item: TodoItem) => summarySpan(item),
    [],
  );

  /* ── vertical scroll sync (body drives, gutter mirrors) ── */
  const onBodyScroll = useCallback((scrollTop: number) => {
    if (gutterTrackRef.current) {
      gutterTrackRef.current.style.transform = `translateY(${-scrollTop}px)`;
    }
  }, []);

  /* ── scroll-to-item (expand ancestors, then center) ── */
  const scrollToItemId = useCallback(
    (id: string) => {
      const anc = ancestorsOf(data, id);
      if (anc.length) {
        const next = new Set(collapsedSet);
        anc.forEach((a) => next.delete(a));
        setCollapsed(next);
      }
      const item = itemIndex.get(id);
      if (item) vp.scrollToMs(effStartMs(item));
      requestAnimationFrame(() => {
        const idx = rowsRef.current.findIndex((r) => r.item.id === id);
        const el = bodyScrollRef.current;
        if (idx >= 0 && el) {
          el.scrollTop = Math.max(
            0,
            idx * rowHeight - el.clientHeight / 2 + rowHeight / 2,
          );
        }
      });
    },
    [data, collapsedSet, setCollapsed, itemIndex, vp, rowHeight],
  );

  /* ── imperative handle ── */
  useImperativeHandle(
    ref,
    () => ({
      scrollToDate: (d) => vp.scrollToMs(Date.parse(d)),
      scrollToItem: (id) => scrollToItemId(id),
      scrollToToday: () => vp.scrollToToday(),
      expandAll: () => setCollapsed(new Set()),
      collapseAll: () => setCollapsed(new Set(parentIds(data))),
      setZoom: (z) => vp.setZoomLevel(z),
      zoomBy: (f) => vp.zoomBy(f),
      zoomToFit: () => vp.zoomToFit(),
    }),
    [vp, scrollToItemId, setCollapsed, data],
  );

  const ctx: GanttContextValue = {
    rows,
    renderItems,
    totalSize,
    rowHeight,
    gutterWidth,
    bodyScrollRef,
    gutterTrackRef,
    onBodyScroll,
    measureRows: () => {},
    viewport: vp.viewport,
    bodyWidth,
    setBodyWidth,
    dataExtent: extent,
    disableGestures,
    onPan: vp.onPan,
    onZoomAt: vp.onZoomAt,
    beginPan: vp.beginPan,
    endPanWithVelocity: vp.endPanWithVelocity,
    namedZoom: vp.namedZoom,
    setZoomLevel: vp.setZoomLevel,
    zoomBy: vp.zoomBy,
    zoomToFit: vp.zoomToFit,
    scrollToToday: vp.scrollToToday,
    scrollToItemId,
    pageBy: vp.pageBy,
    nowMs,
    showTodayLine,
    resolveColor,
    geometryFor,
    summarySpanFor,
    statusOptions,
    priorityOptions,
    labelOptions,
    showWeekendShading,
    isCollapsed,
    toggleCollapse,
    selectedId: selectedVal,
    select,
    onTaskClick,
    renderTooltip,
    focusedId,
    setFocusedId,
  };

  return (
    <GanttContext.Provider value={ctx}>
      <div
        role="group"
        aria-label={ariaLabel ?? "Gantt timeline"}
        className={cn("text-foreground", className)}
      >
        {children}
      </div>
    </GanttContext.Provider>
  );
});

